1	import { useState } from "react";
2	import { AppLayout } from "@/components/layout";
3	import { useListEvents, useBulkUpdateEvents, useDeleteEvent, useListSources, useCreateEvent, useUpdateEvent } from "@workspace/api-client-react";
4	import type { UpdateEventRequest, Event as ApiEvent } from "@workspace/api-client-react/src/generated/api.schemas";
5	import { Card } from "@/components/ui/card";
6	import { Button } from "@/components/ui/button";
7	import { Badge } from "@/components/ui/badge";
8	import { Input } from "@/components/ui/input";
9	import { Label } from "@/components/ui/label";
10	import { Textarea } from "@/components/ui/textarea";
11	import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
12	import { Checkbox } from "@/components/ui/checkbox";
13	import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogFooter } from "@/components/ui/dialog";
14	import { format } from "date-fns";
15	import { it } from "date-fns/locale";
16	import { Search, Plus, AlertTriangle, CheckCircle2, XCircle, MapPin, Clock, Pencil, ChevronUp, ChevronDown, ChevronsUpDown } from "lucide-react";
17	import { useQueryClient } from "@tanstack/react-query";
18	import { useToast } from "@/components/ui/use-toast";
19	
20	export default function Eventi() {
21	  const [statusFilter, setStatusFilter] = useState<string>("all");
22	  const [sourceFilter, setSourceFilter] = useState<string>("all");
23	  const [searchTerm, setSearchTerm] = useState("");
24	  const [selectedIds, setSelectedIds] = useState<number[]>([]);
25	  const [sortCol, setSortCol] = useState<string | null>(null);
26	  const [sortDir, setSortDir] = useState<"asc" | "desc">("asc");
27	
28	  const { data: eventsData, isLoading } = useListEvents({
29	    status: statusFilter !== "all" ? statusFilter : undefined,
30	    sourceId: sourceFilter !== "all" ? Number(sourceFilter) : undefined,
31	    search: searchTerm || undefined,
32	    limit: 50,
33	  });
34	
35	  const { data: sources } = useListSources();
36	  const bulkMutation = useBulkUpdateEvents();
37	  const deleteMutation = useDeleteEvent();
38	  const createMutation = useCreateEvent();
39	  const updateMutation = useUpdateEvent();
40	  const queryClient = useQueryClient();
41	  const { toast } = useToast();
42	
43	  const [addOpen, setAddOpen] = useState(false);
44	  const [newTitle, setNewTitle] = useState("");
45	  const [newDateStart, setNewDateStart] = useState("");
46	  const [newDateEnd, setNewDateEnd] = useState("");
47	  const [newLocation, setNewLocation] = useState("");
48	  const [newDescription, setNewDescription] = useState("");
49	  const [newPrice, setNewPrice] = useState("");
50	  const [newUrl, setNewUrl] = useState("");
51	  const [isSaving, setIsSaving] = useState(false);
52	
53	  const [editingEvent, setEditingEvent] = useState<ApiEvent | null>(null);
54	  const [editForm, setEditForm] = useState<UpdateEventRequest>({});
55	
56	  const openEdit = (event: ApiEvent) => {
57	    setEditingEvent(event);
58	    setEditForm({
59	      title: event.title,
60	      dateStart: event.dateStart ?? null,
61	      dateEnd: event.dateEnd ?? null,
62	      dateDisplay: event.dateDisplay ?? null,
63	      location: event.location ?? null,
64	      descriptionRaw: event.descriptionRaw ?? null,
65	      price: event.price ?? null,
66	      sourceUrl: event.sourceUrl ?? null,
67	      status: event.status,
68	    });
69	  };
70	
71	  const handleUpdate = async () => {
72	    if (!editingEvent) return;
73	    if (!editForm.title?.trim()) {
74	      toast({ title: "Il titolo è obbligatorio", variant: "destructive" });
75	      return;
76	    }
77	    setIsSaving(true);
78	    try {
79	      await updateMutation.mutateAsync({ id: editingEvent.id, data: editForm });
80	      toast({ title: "Evento aggiornato" });
81	      queryClient.invalidateQueries({ queryKey: ["/api/events"] });
82	      setEditingEvent(null);
83	    } catch {
84	      toast({ title: "Errore nell'aggiornamento", variant: "destructive" });
85	    } finally {
86	      setIsSaving(false);
87	    }
88	  };
89	
90	  const openAdd = () => {
91	    setNewTitle(""); setNewDateStart(""); setNewDateEnd("");
92	    setNewLocation(""); setNewDescription(""); setNewPrice(""); setNewUrl("");
93	    setAddOpen(true);
94	  };
95	
96	  const handleCreate = async () => {
97	    if (!newTitle.trim()) {
98	      toast({ title: "Il titolo è obbligatorio", variant: "destructive" });
99	      return;
100	    }
101	    setIsSaving(true);
102	    try {
103	      await createMutation.mutateAsync({
104	        data: {
105	          title: newTitle,
106	          dateStart: newDateStart || null,
107	          dateEnd: newDateEnd || null,
108	          location: newLocation || null,
109	          descriptionRaw: newDescription || null,
110	          price: newPrice || null,
111	          sourceUrl: newUrl || null,
112	          sourceType: "manual",
113	          status: "pending",
114	        },
115	      });
116	      toast({ title: "Evento creato" });
117	      queryClient.invalidateQueries({ queryKey: ["/api/events"] });
118	      setAddOpen(false);
119	    } catch {
120	      toast({ title: "Errore nella creazione", variant: "destructive" });
121	    } finally {
122	      setIsSaving(false);
123	    }
124	  };
125	
126	  const handleBulkAction = async (action: string) => {
127	    if (selectedIds.length === 0) return;
128	    try {
129	      await bulkMutation.mutateAsync({ data: { ids: selectedIds, action } });
130	      toast({ title: "Eventi aggiornati" });
131	      setSelectedIds([]);
132	      queryClient.invalidateQueries({ queryKey: ["/api/events"] });
133	    } catch (e) {
134	      toast({ title: "Errore", variant: "destructive" });
135	    }
136	  };
137	
138	  const toggleAll = (checked: boolean) => {
139	    if (checked && eventsData) setSelectedIds(eventsData.events.map(e => e.id));
140	    else setSelectedIds([]);
141	  };
142	
143	  const toggleOne = (id: number) => {
144	    setSelectedIds(prev => prev.includes(id) ? prev.filter(i => i !== id) : [...prev, id]);
145	  };
146	
147	  const getStatusBadge = (status: string) => {
148	    switch (status) {
149	      case 'pending': return <Badge className="bg-amber-100 text-amber-700 border-amber-200 hover:bg-amber-100">In attesa</Badge>;
150	      case 'approved': return <Badge className="bg-green-100 text-green-700 border-green-200 hover:bg-green-100">Approvato</Badge>;
151	      case 'rejected': return <Badge className="bg-red-100 text-red-700 border-red-200 hover:bg-red-100">Rifiutato</Badge>;
152	      default: return <Badge variant="outline">{status}</Badge>;
153	    }
154	  };
155	
156	  const handleSort = (col: string) => {
157	    if (sortCol === col) setSortDir(d => d === "asc" ? "desc" : "asc");
158	    else { setSortCol(col); setSortDir("asc"); }
159	  };
160	
161	  const sortedEvents = [...(eventsData?.events ?? [])].sort((a, b) => {
162	    if (!sortCol) return 0;
163	    let av: string, bv: string;
164	    if (sortCol === "date") {
165	      av = a.dateStart ?? "";
166	      bv = b.dateStart ?? "";
167	    } else if (sortCol === "source") {
168	      av = (a.sourceName ?? "Manuale").toLowerCase();
169	      bv = (b.sourceName ?? "Manuale").toLowerCase();
170	    } else if (sortCol === "status") {
171	      av = a.status;
172	      bv = b.status;
173	    } else if (sortCol === "title") {
174	      av = a.title.toLowerCase();
175	      bv = b.title.toLowerCase();
176	    } else if (sortCol === "location") {
177	      av = (a.location ?? "").toLowerCase();
178	      bv = (b.location ?? "").toLowerCase();
179	    } else return 0;
180	    if (av < bv) return sortDir === "asc" ? -1 : 1;
181	    if (av > bv) return sortDir === "asc" ? 1 : -1;
182	    return 0;
183	  });
184	
185	  const SortIcon = ({ col }: { col: string }) => {
186	    if (sortCol !== col) return <ChevronsUpDown className="w-3.5 h-3.5 ml-1 opacity-40" />;
187	    return sortDir === "asc"
188	      ? <ChevronUp className="w-3.5 h-3.5 ml-1" />
189	      : <ChevronDown className="w-3.5 h-3.5 ml-1" />;
190	  };
191	
192	  return (
193	    <AppLayout>
194	      <div className="flex flex-col sm:flex-row items-start sm:items-center justify-between gap-4 mb-8">
195	        <div>
196	          <h1 className="text-3xl font-bold font-display text-foreground tracking-tight">Eventi</h1>
197	          <p className="text-muted-foreground mt-1">Gestisci, revisiona e approva gli eventi per la newsletter.</p>
198	        </div>
199	        <Button className="shadow-md" onClick={openAdd}>
200	          <Plus className="w-4 h-4 mr-2" />
201	          Aggiungi Evento
202	        </Button>
203	      </div>
204	
205	      <Dialog open={addOpen} onOpenChange={setAddOpen}>
206	        <DialogContent className="sm:max-w-lg">
207	          <DialogHeader>
208	            <DialogTitle>Nuovo Evento</DialogTitle>
209	          </DialogHeader>
210	          <div className="space-y-4 py-2">
211	            <div className="space-y-1.5">
212	              <Label htmlFor="ev-title">Titolo *</Label>
213	              <Input id="ev-title" value={newTitle} onChange={e => setNewTitle(e.target.value)} placeholder="Es. Mercato di Natale in Piazza" />
214	            </div>
215	            <div className="grid grid-cols-2 gap-4">
216	              <div className="space-y-1.5">
217	                <Label htmlFor="ev-start">Data inizio</Label>
218	                <Input id="ev-start" type="date" value={newDateStart} onChange={e => setNewDateStart(e.target.value)} />
219	              </div>
220	              <div className="space-y-1.5">
221	                <Label htmlFor="ev-end">Data fine</Label>
222	                <Input id="ev-end" type="date" value={newDateEnd} onChange={e => setNewDateEnd(e.target.value)} />
223	              </div>
224	            </div>
225	            <div className="space-y-1.5">
226	              <Label htmlFor="ev-location">Luogo</Label>
227	              <Input id="ev-location" value={newLocation} onChange={e => setNewLocation(e.target.value)} placeholder="Es. Piazza Repubblica, Varese" />
228	            </div>
229	            <div className="space-y-1.5">
230	              <Label htmlFor="ev-desc">Descrizione</Label>
231	              <Textarea id="ev-desc" value={newDescription} onChange={e => setNewDescription(e.target.value)} placeholder="Breve descrizione dell'evento..." rows={3} />
232	            </div>
233	            <div className="grid grid-cols-2 gap-4">
234	              <div className="space-y-1.5">
235	                <Label htmlFor="ev-price">Prezzo</Label>
236	                <Input id="ev-price" value={newPrice} onChange={e => setNewPrice(e.target.value)} placeholder="Es. Gratuito / €10" />
237	              </div>
238	              <div className="space-y-1.5">
239	                <Label htmlFor="ev-url">URL</Label>
240	                <Input id="ev-url" type="url" value={newUrl} onChange={e => setNewUrl(e.target.value)} placeholder="https://..." />
241	              </div>
242	            </div>
243	          </div>
244	          <DialogFooter>
245	            <Button variant="outline" onClick={() => setAddOpen(false)} disabled={isSaving}>Annulla</Button>
246	            <Button onClick={handleCreate} disabled={isSaving}>
247	              {isSaving ? "Salvataggio..." : "Crea Evento"}
248	            </Button>
249	          </DialogFooter>
250	        </DialogContent>
251	      </Dialog>
252	
253	      <Dialog open={!!editingEvent} onOpenChange={open => { if (!open) setEditingEvent(null); }}>
254	        <DialogContent className="sm:max-w-lg">
255	          <DialogHeader>
256	            <DialogTitle>Modifica Evento</DialogTitle>
257	          </DialogHeader>
258	          <div className="space-y-4 py-2">
259	            <div className="space-y-1.5">
260	              <Label htmlFor="edit-title">Titolo *</Label>
261	              <Input id="edit-title" value={editForm.title ?? ""} onChange={e => setEditForm(f => ({ ...f, title: e.target.value }))} />
262	            </div>
263	            <div className="grid grid-cols-2 gap-4">
264	              <div className="space-y-1.5">
265	                <Label htmlFor="edit-start">Data inizio</Label>
266	                <Input id="edit-start" type="date" value={editForm.dateStart ?? ""} onChange={e => setEditForm(f => ({ ...f, dateStart: e.target.value || null }))} />
267	              </div>
268	              <div className="space-y-1.5">
269	                <Label htmlFor="edit-end">Data fine</Label>
270	                <Input id="edit-end" type="date" value={editForm.dateEnd ?? ""} onChange={e => setEditForm(f => ({ ...f, dateEnd: e.target.value || null }))} />
271	              </div>
272	            </div>
273	            <div className="space-y-1.5">
274	              <Label htmlFor="edit-display">Data visualizzata</Label>
275	              <Input id="edit-display" value={editForm.dateDisplay ?? ""} onChange={e => setEditForm(f => ({ ...f, dateDisplay: e.target.value || null }))} placeholder="Es. 5–7 aprile 2025" />
276	            </div>
277	            <div className="space-y-1.5">
278	              <Label htmlFor="edit-location">Luogo</Label>
279	              <Input id="edit-location" value={editForm.location ?? ""} onChange={e => setEditForm(f => ({ ...f, location: e.target.value || null }))} />
280	            </div>
281	            <div className="space-y-1.5">
282	              <Label htmlFor="edit-desc">Descrizione</Label>
283	              <Textarea id="edit-desc" value={editForm.descriptionRaw ?? ""} onChange={e => setEditForm(f => ({ ...f, descriptionRaw: e.target.value || null }))} rows={3} />
284	            </div>
285	            <div className="grid grid-cols-2 gap-4">
286	              <div className="space-y-1.5">
287	                <Label htmlFor="edit-price">Prezzo</Label>
288	                <Input id="edit-price" value={editForm.price ?? ""} onChange={e => setEditForm(f => ({ ...f, price: e.target.value || null }))} placeholder="Es. Gratuito / €10" />
289	              </div>
290	              <div className="space-y-1.5">
291	                <Label htmlFor="edit-url">URL</Label>
292	                <Input id="edit-url" type="url" value={editForm.sourceUrl ?? ""} onChange={e => setEditForm(f => ({ ...f, sourceUrl: e.target.value || null }))} placeholder="https://..." />
293	              </div>
294	            </div>
295	            <div className="space-y-1.5">
296	              <Label htmlFor="edit-status">Stato</Label>
297	              <Select value={editForm.status ?? "pending"} onValueChange={v => setEditForm(f => ({ ...f, status: v }))}>
298	                <SelectTrigger id="edit-status" className="bg-background">
299	                  <SelectValue />
300	                </SelectTrigger>
301	                <SelectContent>
302	                  <SelectItem value="pending">In attesa</SelectItem>
303	                  <SelectItem value="approved">Approvato</SelectItem>
304	                  <SelectItem value="rejected">Rifiutato</SelectItem>
305	                </SelectContent>
306	              </Select>
307	            </div>
308	          </div>
309	          <DialogFooter>
310	            <Button variant="outline" onClick={() => setEditingEvent(null)} disabled={isSaving}>Annulla</Button>
311	            <Button onClick={handleUpdate} disabled={isSaving}>
312	              {isSaving ? "Salvataggio..." : "Salva Modifiche"}
313	            </Button>
314	          </DialogFooter>
315	        </DialogContent>
316	      </Dialog>
317	
318	      <div className="bg-card p-4 rounded-xl border border-border/50 mb-6 flex flex-col md:flex-row gap-4 shadow-sm">
319	        <div className="flex-1 relative">
320	          <Search className="w-4 h-4 absolute left-3 top-1/2 -translate-y-1/2 text-muted-foreground" />
321	          <Input 
322	            placeholder="Cerca evento..." 
323	            className="pl-9 bg-background"
324	            value={searchTerm}
325	            onChange={e => setSearchTerm(e.target.value)}
326	          />
327	        </div>
328	        <div className="flex flex-wrap gap-3">
329	          <Select value={statusFilter} onValueChange={setStatusFilter}>
330	            <SelectTrigger className="w-[140px] bg-background">
331	              <SelectValue placeholder="Stato" />
332	            </SelectTrigger>
333	            <SelectContent>
334	              <SelectItem value="all">Tutti gli stati</SelectItem>
335	              <SelectItem value="pending">In attesa</SelectItem>
336	              <SelectItem value="approved">Approvati</SelectItem>
337	              <SelectItem value="rejected">Rifiutati</SelectItem>
338	            </SelectContent>
339	          </Select>
340	
341	          <Select value={sourceFilter} onValueChange={setSourceFilter}>
342	            <SelectTrigger className="w-[180px] bg-background">
343	              <SelectValue placeholder="Tutte le fonti" />
344	            </SelectTrigger>
345	            <SelectContent>
346	              <SelectItem value="all">Tutte le fonti</SelectItem>
347	              {sources?.map(s => <SelectItem key={s.id} value={s.id.toString()}>{s.name}</SelectItem>)}
348	            </SelectContent>
349	          </Select>
350	        </div>
351	      </div>
352	
353	      {selectedIds.length > 0 && (
354	        <div className="bg-primary/5 border border-primary/20 p-3 rounded-lg mb-4 flex items-center justify-between animate-in fade-in slide-in-from-top-2">
355	          <span className="text-sm font-medium text-primary ml-2">{selectedIds.length} eventi selezionati</span>
356	          <div className="flex gap-2">
357	            <Button size="sm" variant="outline" className="border-green-200 text-green-700 hover:bg-green-50" onClick={() => handleBulkAction('approve')}>
358	              <CheckCircle2 className="w-4 h-4 mr-1" /> Approva
359	            </Button>
360	            <Button size="sm" variant="outline" className="border-red-200 text-red-700 hover:bg-red-50" onClick={() => handleBulkAction('reject')}>
361	              <XCircle className="w-4 h-4 mr-1" /> Rifiuta
362	            </Button>
363	          </div>
364	        </div>
365	      )}
366	
367	      <div className="bg-card rounded-xl border border-border/50 shadow-sm overflow-hidden">
368	        <div className="overflow-x-auto">
369	          <table className="w-full text-sm text-left">
370	            <thead className="bg-muted/30 text-muted-foreground font-medium border-b border-border/50">
371	              <tr>
372	                <th className="p-4 w-12"><Checkbox checked={eventsData?.events?.length > 0 && selectedIds.length === eventsData?.events?.length} onCheckedChange={toggleAll} /></th>
373	                <th className="p-4 min-w-[250px]">
374	                  <button className="flex items-center hover:text-foreground transition-colors" onClick={() => handleSort("title")}>Titolo <SortIcon col="title" /></button>
375	                </th>
376	                <th className="p-4">
377	                  <button className="flex items-center hover:text-foreground transition-colors" onClick={() => handleSort("date")}>Data <SortIcon col="date" /></button>
378	                </th>
379	                <th className="p-4">
380	                  <button className="flex items-center hover:text-foreground transition-colors" onClick={() => handleSort("location")}>Luogo <SortIcon col="location" /></button>
381	                </th>
382	                <th className="p-4">
383	                  <button className="flex items-center hover:text-foreground transition-colors" onClick={() => handleSort("source")}>Fonte <SortIcon col="source" /></button>
384	                </th>
385	                <th className="p-4">
386	                  <button className="flex items-center hover:text-foreground transition-colors" onClick={() => handleSort("status")}>Stato <SortIcon col="status" /></button>
387	                </th>
388	                <th className="p-4 text-right">Azioni</th>
389	              </tr>
390	            </thead>
391	            <tbody className="divide-y divide-border/30">
392	              {isLoading ? (
393	                <tr><td colSpan={7} className="p-8 text-center text-muted-foreground animate-pulse">Caricamento...</td></tr>
394	              ) : sortedEvents.length === 0 ? (
395	                <tr><td colSpan={7} className="p-12 text-center text-muted-foreground">Nessun evento trovato.</td></tr>
396	              ) : (
397	                sortedEvents.map(event => (
398	                  <tr key={event.id} className="hover:bg-muted/10 transition-colors group">
399	                    <td className="p-4"><Checkbox checked={selectedIds.includes(event.id)} onCheckedChange={() => toggleOne(event.id)} /></td>
400	                    <td className="p-4 min-w-[250px]">
401	                      <div className="font-medium text-foreground text-base">{event.title}</div>
402	                    </td>
403	                    <td className="p-4 text-muted-foreground text-xs whitespace-nowrap">
404	                      <div className="flex items-center gap-2">
405	                        <Clock className="w-3 h-3 shrink-0" />
406	                        {event.dateDisplay || (event.dateStart ? format(new Date(event.dateStart), 'dd MMM yyyy', { locale: it }) : 'Sconosciuta')}
407	                        {event.dateParseConfidence === 'low' && (
408	                          <AlertTriangle className="w-3 h-3 text-amber-500" title="Data parsing a bassa confidenza" />
409	                        )}
410	                      </div>
411	                    </td>
412	                    <td className="p-4 text-muted-foreground">
413	                      {event.location ? (
414	                        <div className="flex items-center gap-1.5 truncate max-w-[200px]">
415	                          <MapPin className="w-3.5 h-3.5 shrink-0" />
416	                          <span className="truncate">{event.location}</span>
417	                        </div>
418	                      ) : '-'}
419	                    </td>
420	                    <td className="p-4">
421	                      <div className="flex flex-col gap-1 items-start">
422	                        <span className="text-xs truncate max-w-[150px]">{event.sourceName || 'Manuale'}</span>
423	                        <Badge variant="outline" className={`text-[10px] uppercase tracking-wider ${event.sourceType === 'manual' ? 'text-purple-600 border-purple-200' : 'text-blue-600 border-blue-200'}`}>
424	                          {event.sourceType}
425	                        </Badge>
426	                      </div>
427	                    </td>
428	                    <td className="p-4">{getStatusBadge(event.status)}</td>
429	                    <td className="p-4 text-right">
430	                      <Button variant="ghost" size="icon" className="text-muted-foreground hover:text-primary" onClick={() => openEdit(event)}>
431	                        <Pencil className="w-4 h-4" />
432	                      </Button>
433	                    </td>
434	                  </tr>
435	                ))
436	              )}
437	            </tbody>
438	          </table>
439	        </div>
440	      </div>
441	    </AppLayout>
442	  );
443	}
